        /* wms-inbound-order-update-sql-oracle.xml - updaetInboundOrderDetail 입고 예정 수량 변경 UPDATE */
		UPDATE TWORK_INFO_IB_DT
		   SET EXPCTQTY = #{expctqty}
             , B2BOBCNFRMYN = 'Y'
			 , UPDATEDATE = #{sysdate}
			 , UPDATEURKEY = #{surkey}
		 WHERE CTKEY = #{ctkey}
		   AND OWKEY = #{owkey}
		   AND ORHDKEY = #{orhdkey}
           AND ICKEY = #{ickey}

/* wms-inbound-order-update-sql-oracle.xml - updateInboundOrderHeader 입고 헤더 B2B출고 확정여부 변경 UPDATE */
UPDATE TWORK_INFO_IB_HD
   SET B2BOBCNFRMYN = 'Y'
     , UPDATEDATE = #{sysdate}
     , UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
  AND OWKEY = #{owkey}
  AND ORHDKEY = #{orhdkey}
